/**
 * Normalize Parsed Document
 *
 * 목적:
 * 1. Upstage Document Parse 응답에서 본문 HTML/Markdown/Text를 안정적으로 추출
 * 2. Form Trigger 입력값(bookTitle, courseName, preferredTerms)을 병합
 * 3. elements 요약 생성
 * 4. table/chart/figure/equation의 base64_encoding을 visualAssets로 분리
 *
 * 다음 노드에서 쓰는 핵심 필드:
 * - sourceDocument
 * - glossarySource
 * - elementSummary
 * - visualAssets
 * - visualAssetMeta
 */

const FORM_NODE_CANDIDATES = [
  "Form Trigger",
  "On form submission",
  "On Form Submission",
];

// 1. Upstage Document Parse 응답 가져오기
let parseResult = $input.first().json;

// n8n/HTTP 응답 형태에 따라 배열로 감싸져 있을 수 있으므로 방어 처리
if (Array.isArray(parseResult)) {
  parseResult = parseResult[0] || {};
}

if (parseResult && Array.isArray(parseResult.data)) {
  parseResult = parseResult.data[0] || {};
}

// 2. Form Trigger 값 가져오기
let form = {};

for (const nodeName of FORM_NODE_CANDIDATES) {
  try {
    const candidate = $(nodeName).first().json || {};
    if (candidate && Object.keys(candidate).length > 0) {
      form = candidate;
      break;
    }
  } catch (error) {
    // 해당 이름의 노드가 없으면 무시
  }
}

// 3. 유틸 함수
function asString(value) {
  if (value === null || value === undefined) return "";
  if (typeof value === "string") return value;
  if (typeof value === "number" || typeof value === "boolean") return String(value);

  try {
    return JSON.stringify(value);
  } catch {
    return "";
  }
}

function getByPath(obj, path) {
  return path.split(".").reduce((acc, key) => {
    if (acc && Object.prototype.hasOwnProperty.call(acc, key)) {
      return acc[key];
    }
    return undefined;
  }, obj);
}

function firstNonEmptyByPaths(obj, paths) {
  for (const path of paths) {
    const value = getByPath(obj, path);
    const text = asString(value).trim();

    if (text) {
      return {
        path,
        text,
      };
    }
  }

  return {
    path: "",
    text: "",
  };
}

function decodeBasicEntities(text) {
  return String(text || "")
    .replaceAll("&nbsp;", " ")
    .replaceAll("&amp;", "&")
    .replaceAll("&lt;", "<")
    .replaceAll("&gt;", ">")
    .replaceAll("&quot;", '"')
    .replaceAll("&#39;", "'");
}

function htmlToPlainText(html) {
  return decodeBasicEntities(
    String(html || "")
      .replace(/<br\s*\/?>/gi, "\n")
      .replace(/<\/p>/gi, "\n")
      .replace(/<\/caption>/gi, "\n")
      .replace(/<\/h[1-6]>/gi, "\n")
      .replace(/<\/tr>/gi, "\n")
      .replace(/<\/td>/gi, " | ")
      .replace(/<[^>]+>/g, " ")
      .replace(/[ \t]+/g, " ")
      .replace(/\n\s+/g, "\n")
      .trim()
  );
}

function getElementHtml(element) {
  return (
    element?.content?.html ||
    element?.html ||
    element?.content?.markdown ||
    element?.markdown ||
    element?.content?.text ||
    element?.text ||
    ""
  );
}

function getElementText(element) {
  const html = getElementHtml(element);

  if (html) {
    return htmlToPlainText(html);
  }

  return asString(element?.text || element?.content?.text || "");
}

function getHtmlId(html) {
  const match = String(html || "").match(/\bid=["']([^"']+)["']/i);
  return match ? match[1] : "";
}

function normalizeCategory(category) {
  const c = String(category || "").toLowerCase();

  if (c === "heading1" || c === "heading2" || c === "heading3") return c;
  if (c === "chart") return "chart";
  if (c === "figure") return "figure";
  if (c === "table") return "table";
  if (c === "equation") return "equation";
  if (c === "caption") return "caption";
  if (c === "list") return "list";
  if (c === "header") return "header";
  if (c === "footer") return "footer";

  return c || "";
}

// 4. elements 배열 수집
function collectElements(obj) {
  const candidates = [
    obj?.elements,
    obj?.content?.elements,
    obj?.result?.elements,
    obj?.output?.elements,
  ];

  for (const candidate of candidates) {
    if (Array.isArray(candidate) && candidate.length > 0) {
      return candidate;
    }
  }

  if (Array.isArray(obj?.pages)) {
    return obj.pages.flatMap((page, pageIndex) => {
      const pageElements =
        page?.elements ||
        page?.content?.elements ||
        page?.result?.elements ||
        [];

      if (!Array.isArray(pageElements)) return [];

      return pageElements.map((element) => ({
        ...element,
        page:
          element.page ||
          element.page_number ||
          page.page ||
          page.page_number ||
          pageIndex + 1,
      }));
    });
  }

  return [];
}

const elements = collectElements(parseResult);

// 5. pages에서 본문 수집
function collectTextFromPages(obj) {
  if (!Array.isArray(obj?.pages)) return "";

  const chunks = [];

  for (const page of obj.pages) {
    const pageTextCandidate = firstNonEmptyByPaths(page, [
      "content.markdown",
      "markdown",
      "content.html",
      "html",
      "content.text",
      "text",
    ]);

    if (pageTextCandidate.text) {
      chunks.push(pageTextCandidate.text);
    }

    const pageElements =
      page?.elements ||
      page?.content?.elements ||
      page?.result?.elements ||
      [];

    if (Array.isArray(pageElements)) {
      for (const element of pageElements) {
        const elementTextCandidate = firstNonEmptyByPaths(element, [
          "content.markdown",
          "markdown",
          "content.html",
          "html",
          "content.text",
          "text",
        ]);

        if (elementTextCandidate.text) {
          chunks.push(elementTextCandidate.text);
        }
      }
    }
  }

  return chunks.join("\n\n").trim();
}

// 6. elements에서 본문 수집
function collectTextFromElements(elements) {
  const chunks = [];

  for (const element of elements) {
    const elementTextCandidate = firstNonEmptyByPaths(element, [
      "content.markdown",
      "markdown",
      "content.html",
      "html",
      "content.text",
      "text",
    ]);

    if (elementTextCandidate.text) {
      chunks.push(elementTextCandidate.text);
    }
  }

  return chunks.join("\n\n").trim();
}

// 7. 본문 추출 우선순위: content.markdown → markdown → content.html → html → text → pages → elements
const directTextCandidate = firstNonEmptyByPaths(parseResult, [
  "content.markdown",
  "markdown",
  "result.markdown",
  "output.markdown",

  "content.html",
  "html",
  "result.html",
  "output.html",

  "content.text",
  "text",
  "result.text",
  "output.text",
]);

let sourceDocument = directTextCandidate.text;
let sourcePath = directTextCandidate.path;

if (!sourceDocument) {
  sourceDocument = collectTextFromPages(parseResult);
  sourcePath = "pages";
}

if (!sourceDocument) {
  sourceDocument = collectTextFromElements(elements);
  sourcePath = "elements";
}

if (!sourceDocument || sourceDocument.trim().length === 0) {
  throw new Error(
    "Upstage Document Parse 응답에서 번역 가능한 markdown/html/text를 찾지 못했습니다. Output JSON 구조를 확인해야 합니다."
  );
}

// 8. base64 관련 유틸
function normalizeBase64Value(value) {
  if (value === null || value === undefined) {
    return {
      base64: "",
      mimeType: "",
      isDataUri: false,
      sourceUrl: "",
    };
  }

  // object 형태로 들어오는 경우 방어 처리
  if (typeof value === "object") {
    const nested =
      value.base64 ||
      value.base64_encoding ||
      value.image_base64 ||
      value.data ||
      value.src ||
      value.url ||
      "";

    return normalizeBase64Value(nested);
  }

  const raw = String(value || "").trim();

  if (!raw) {
    return {
      base64: "",
      mimeType: "",
      isDataUri: false,
      sourceUrl: "",
    };
  }

  // 이미 URL인 경우
  if (/^https?:\/\//i.test(raw)) {
    return {
      base64: "",
      mimeType: "",
      isDataUri: false,
      sourceUrl: raw,
    };
  }

  // data:image/png;base64,... 형태
  const dataUriMatch = raw.match(/^data:([^;]+);base64,(.+)$/i);

  if (dataUriMatch) {
    return {
      base64: dataUriMatch[2].replace(/\s+/g, ""),
      mimeType: dataUriMatch[1],
      isDataUri: true,
      sourceUrl: "",
    };
  }

  const compact = raw.replace(/\s+/g, "");

  return {
    base64: compact,
    mimeType: guessMimeTypeFromBase64(compact),
    isDataUri: false,
    sourceUrl: "",
  };
}

function guessMimeTypeFromBase64(base64) {
  const s = String(base64 || "").slice(0, 20);

  // JPEG base64는 보통 /9j/ 로 시작합니다.
  if (s.startsWith("/9j/")) return "image/jpeg";

  // PNG base64는 보통 iVBOR 로 시작합니다.
  if (s.startsWith("iVBOR")) return "image/png";

  // GIF
  if (s.startsWith("R0lGOD")) return "image/gif";

  // WEBP
  if (s.startsWith("UklGR")) return "image/webp";

  // Upstage table/chart crop은 현재 결과상 JPEG로 들어옵니다.
  return "image/jpeg";
}

function getVisualCandidate(element) {
  const candidates = [
    element?.base64_encoding,
    element?.base64,
    element?.image_base64,
    element?.image,
    element?.src,
    element?.url,
    element?.content?.base64_encoding,
    element?.content?.base64,
    element?.content?.image_base64,
    element?.content?.image,
    element?.content?.src,
    element?.content?.url,
  ];

  for (const candidate of candidates) {
    const normalized = normalizeBase64Value(candidate);

    if (normalized.base64 || normalized.sourceUrl) {
      return normalized;
    }
  }

  return {
    base64: "",
    mimeType: "",
    isDataUri: false,
    sourceUrl: "",
  };
}

function isVisualCategory(category) {
  return ["table", "chart", "figure", "image", "equation"].includes(
    String(category || "").toLowerCase()
  );
}

// 9. visualAssets 추출
const visualAssets = elements
  .map((element, index) => {
    const category = normalizeCategory(element?.category || element?.type || element?.label || "");
    const html = getElementHtml(element);
    const htmlId = getHtmlId(html);
    const elementId =
      element?.id !== undefined && element?.id !== null
        ? String(element.id)
        : htmlId || `visual_${index + 1}`;

    const visualCandidate = getVisualCandidate(element);

    return {
      id: elementId,
      category,
      page: element?.page || element?.page_number || null,
      html,
      text: getElementText(element),
      coordinates: Array.isArray(element?.coordinates) ? element.coordinates : [],
      base64: visualCandidate.base64,
      mimeType: visualCandidate.mimeType || "image/jpeg",
      sourceUrl: visualCandidate.sourceUrl,
      base64Length: visualCandidate.base64 ? visualCandidate.base64.length : 0,
    };
  })
  .filter((asset) => {
    return isVisualCategory(asset.category) && (asset.base64 || asset.sourceUrl);
  });

// 10. glossary용 발췌문
const glossarySource = sourceDocument.slice(0, 16000);

// 11. element summary 생성
const elementSummary = elements.slice(0, 80).map((element, index) => {
  const category = normalizeCategory(element?.category || element?.type || element?.label || "");
  const html = getElementHtml(element);
  const visualCandidate = getVisualCandidate(element);

  return {
    index: index + 1,
    id:
      element?.id !== undefined && element?.id !== null
        ? String(element.id)
        : getHtmlId(html) || "",
    page: element?.page || element?.page_number || null,
    category,
    preview: html ? html.slice(0, 220) : getElementText(element).slice(0, 220),
    hasBase64: Boolean(visualCandidate.base64),
    base64Length: visualCandidate.base64 ? visualCandidate.base64.length : 0,
  };
});

// 12. visual asset summary 생성
const visualAssetSummary = visualAssets.map((asset) => ({
  id: asset.id,
  category: asset.category,
  page: asset.page,
  mimeType: asset.mimeType,
  base64Length: asset.base64Length,
  hasSourceUrl: Boolean(asset.sourceUrl),
  preview: asset.text ? asset.text.slice(0, 160) : asset.html.slice(0, 160),
}));

// 13. 최종 반환
return [
  {
    json: {
      bookTitle:
        form.book_title ||
        form.bookTitle ||
        form["책/챕터 제목"] ||
        "Translated Textbook",

      courseName:
        form.course_name ||
        form.courseName ||
        form["과목명"] ||
        "",

      preferredTerms:
        form.preferred_terms ||
        form.preferredTerms ||
        form["선호 번역어"] ||
        form["선호 번역어 / 고정 용어"] ||
        "",

      sourceDocument,
      glossarySource,
      sourcePath,

      parseMeta: {
        sourcePath,
        sourceLength: sourceDocument.length,
        glossarySourceLength: glossarySource.length,
        elementCount: elements.length,
        pageCount: Array.isArray(parseResult?.pages)
          ? parseResult.pages.length
          : parseResult?.usage?.pages || null,
        hasContentMarkdown: Boolean(parseResult?.content?.markdown || parseResult?.markdown),
        hasContentHtml: Boolean(parseResult?.content?.html || parseResult?.html),
        model: parseResult?.model || "",
        ocr: parseResult?.ocr ?? null,
      },

      elementSummary,

      visualAssets,
      visualAssetSummary,
      visualAssetMeta: {
        count: visualAssets.length,
        categories: visualAssets.map((asset) => asset.category),
        ids: visualAssets.map((asset) => asset.id),
      },

      sourcePreview: sourceDocument.slice(0, 1000),
    },
  },
];

