// 1. Normalize Parsed Document 결과 가져오기
const base = $("Normalize Parsed Document").first().json;

// 2. Solar Extract Glossary 응답 가져오기
const solarResponse = $input.first().json;

// 3. Solar 응답 본문 추출
let raw =
  solarResponse.choices?.[0]?.message?.content ??
  solarResponse.choices?.[0]?.text ??
  solarResponse.content ??
  solarResponse.text ??
  "";

raw = String(raw).trim();

if (!raw) {
  throw new Error("Solar 응답에서 content를 찾지 못했습니다.");
}

// 4. 코드블록 제거
raw = raw
  .replace(/^```json\s*/i, "")
  .replace(/^```\s*/i, "")
  .replace(/\s*```$/i, "")
  .trim();

// 5. JSON 파싱 보조 함수들
function normalizeGlossary(parsed) {
  if (Array.isArray(parsed)) {
    return parsed;
  }

  if (parsed && typeof parsed === "object") {
    if (Array.isArray(parsed.terms)) return parsed.terms;
    if (Array.isArray(parsed.glossary)) return parsed.glossary;
    if (Array.isArray(parsed.items)) return parsed.items;

    // 단일 객체 하나만 온 경우
    if (parsed.source && parsed.ko) return [parsed];
  }

  return [];
}

function tryParseJson(text) {
  try {
    return JSON.parse(text);
  } catch {
    return null;
  }
}

function extractJsonArrayText(text) {
  const start = text.indexOf("[");
  const end = text.lastIndexOf("]");

  if (start === -1 || end === -1 || end <= start) {
    return null;
  }

  return text.slice(start, end + 1);
}

// 여러 JSON 객체가 공백으로 이어진 경우를 처리합니다.
// 예: {"source":"a"} {"source":"b"} {"source":"c"}
function extractBalancedJsonObjects(text) {
  const objects = [];

  let start = -1;
  let depth = 0;
  let inString = false;
  let escape = false;

  for (let i = 0; i < text.length; i++) {
    const ch = text[i];

    if (escape) {
      escape = false;
      continue;
    }

    if (ch === "\\") {
      escape = true;
      continue;
    }

    if (ch === "\"") {
      inString = !inString;
      continue;
    }

    if (inString) {
      continue;
    }

    if (ch === "{") {
      if (depth === 0) {
        start = i;
      }
      depth++;
    }

    if (ch === "}") {
      depth--;

      if (depth === 0 && start !== -1) {
        const candidate = text.slice(start, i + 1);
        const parsed = tryParseJson(candidate);

        if (parsed) {
          objects.push(parsed);
        }

        start = -1;
      }
    }
  }

  return objects;
}

// 6. 파싱 시도 순서
let glossary = [];
let parseStrategy = "";

// A. 응답 전체가 정상 JSON인 경우
const parsedWhole = tryParseJson(raw);
glossary = normalizeGlossary(parsedWhole);

if (glossary.length > 0) {
  parseStrategy = "whole_json";
}

// B. 응답 안에 JSON 배열이 들어 있는 경우
if (glossary.length === 0) {
  const arrayText = extractJsonArrayText(raw);

  if (arrayText) {
    const parsedArray = tryParseJson(arrayText);
    glossary = normalizeGlossary(parsedArray);

    if (glossary.length > 0) {
      parseStrategy = "json_array_inside_text";
    }
  }
}

// C. JSON 객체 여러 개가 이어진 경우
if (glossary.length === 0) {
  const objects = extractBalancedJsonObjects(raw);
  glossary = objects.flatMap((obj) => normalizeGlossary(obj));

  if (glossary.length > 0) {
    parseStrategy = "multiple_json_objects";
  }
}

if (glossary.length === 0) {
  throw new Error(
    "용어사전을 파싱하지 못했습니다. Solar 응답 원문 앞부분: " + raw.slice(0, 1200)
  );
}

// 7. 필드 정리
glossary = glossary
  .filter((item) => item && typeof item === "object")
  .map((item) => ({
    source: String(item.source || "").trim(),
    ko: String(item.ko || "").trim(),
    note: String(item.note || "").trim(),
  }))
  .filter((item) => item.source && item.ko);

// 8. 중복 제거
const seen = new Set();

glossary = glossary.filter((item) => {
  const key = item.source.toLowerCase();

  if (seen.has(key)) {
    return false;
  }

  seen.add(key);
  return true;
});

// 9. 너무 많은 경우 데모 안정성을 위해 20개로 제한
glossary = glossary.slice(0, 20);

// 10. 다음 노드에서 쓰기 좋은 형태로 반환
return [
  {
    json: {
      ...base,

      glossary,
      glossaryJson: JSON.stringify(glossary, null, 2),

      glossaryPreview: glossary
        .map((item, index) => {
          return `${index + 1}. ${item.source} → ${item.ko} (${item.note})`;
        })
        .join("\n"),

      glossaryMeta: {
        termCount: glossary.length,
        rawLength: raw.length,
        parseStrategy,
      },

      glossaryRawPreview: raw.slice(0, 1200),
    },
  },
];

const data = $input.first().json;

// 반드시 실제 Notion 부모 페이지 ID로 교체하십시오.
const NOTION_PARENT_PAGE_ID = "35f62647393980f1b62bf5e942a796c2";

if (
  !NOTION_PARENT_PAGE_ID ||
  NOTION_PARENT_PAGE_ID.includes("여기에")
) {
  throw new Error("NOTION_PARENT_PAGE_ID를 실제 Notion 부모 페이지 ID로 교체해야 합니다.");
}

const title = data.bookTitle || "번역 학습 노트";
const courseName = data.courseName || "미입력";
const glossary = Array.isArray(data.glossary) ? data.glossary : [];
const parseMeta = data.parseMeta || {};
const translationMeta = data.translationMeta || {};
