function decodeBasicEntities(text) {
  return String(text || "")
    .replaceAll("&nbsp;", " ")
    .replaceAll("&amp;", "&")
    .replaceAll("&lt;", "<")
    .replaceAll("&gt;", ">")
    .replaceAll("&quot;", '"')
    .replaceAll("&#39;", "'");
}

function htmlToText(html) {
  return decodeBasicEntities(
    String(html || "")
      .replace(/<br\s*\/?>/gi, "\n")
      .replace(/<\/p>/gi, "\n")
      .replace(/<\/caption>/gi, "\n")
      .replace(/<\/h[1-6]>/gi, "\n")
      .replace(/<[^>]+>/g, " ")
      .replace(/[ \t]+/g, " ")
      .replace(/\n\s+/g, "\n")
      .trim()
  );
}

function getAttr(html, attrName) {
  const re = new RegExp(`${attrName}=["']([^"']+)["']`, "i");
  const match = String(html || "").match(re);
  return match ? match[1] : "";
}

function getElementId(html, fallback) {
  return getAttr(html, "id") || fallback;
}

function extractFontSize(html) {
  const style = getAttr(html, "style");
  const match = style.match(/font-size\s*:\s*(\d+)px/i);
  return match ? Number(match[1]) : null;
}

function classifyBlock(rawHtml) {
  const html = String(rawHtml || "");
  const lower = html.toLowerCase();

  if (lower.match(/^<br>\s*<header/) || lower.startsWith("<header")) return "header";
  if (lower.match(/^<br>\s*<footer/) || lower.startsWith("<footer")) return "footer";
  if (lower.startsWith("<figure")) return "figure";
  if (lower.startsWith("<table")) return "table";
  if (lower.startsWith("<caption")) return "caption";
  if (lower.match(/^<h[1-6]/)) return "heading";
  if (lower.includes("data-category='list'") || lower.includes('data-category="list"')) return "list";

  const text = htmlToText(html);
  const fontSize = extractFontSize(html);

  // 섹션 번호형 제목: 7.4.1 Evaluating Classifiers
  if (/^\d+(\.\d+)+\s+/.test(text) && text.length <= 120) return "heading";

  // 폰트가 크고 짧은 문장은 제목으로 승격
  if (fontSize && fontSize >= 20 && text.length <= 120) return "heading";

  return "paragraph";
}

function shouldDropBlock(block) {
  const text = String(block.text || "").replace(/\s+/g, " ").trim();

  // 일반 원서/논문 PDF에서 header/footer는 대부분 running header/page number입니다.
  if (block.type === "header" || block.type === "footer") return true;

  // 혹시 header로 분류되지 않았어도 순수 페이지 번호는 제거
  if (/^\d{1,5}$/.test(text)) return true;
  if (/^p\.?\s*\d{1,5}$/i.test(text)) return true;

  return false;
}

function extractRowsFromTableHtml(html, tableId) {
  const rows = [];
  const trMatches = String(html || "").match(/<tr\b[\s\S]*?<\/tr>/gi) || [];

  trMatches.forEach((tr, rowIndex) => {
    const cellMatches = tr.match(/<t[dh]\b[\s\S]*?<\/t[dh]>/gi) || [];
    const row = [];

    cellMatches.forEach((cellHtml, cellIndex) => {
      const text = htmlToText(cellHtml);
      const colspanMatch = cellHtml.match(/colspan=["']?(\d+)["']?/i);
      const rowspanMatch = cellHtml.match(/rowspan=["']?(\d+)["']?/i);

      row.push({
        id: `${tableId}_r${rowIndex}_c${cellIndex}`,
        text,
        colspan: colspanMatch ? Number(colspanMatch[1]) : 1,
        rowspan: rowspanMatch ? Number(rowspanMatch[1]) : 1,
      });
    });

    if (row.length > 0) rows.push(row);
  });

  return rows;
}

function extractImageSrc(rawHtml) {
  const html = String(rawHtml || "");
  const srcMatch = html.match(/<img[^>]+src=["']([^"']+)["']/i);
  if (srcMatch?.[1]) return srcMatch[1];

  // 현재 demo.pdf처럼 data-coord만 있는 경우를 기록
  const coordMatch = html.match(/<img[^>]+data-coord=["']([^"']+)["']/i);
  if (coordMatch?.[1]) return "";

  return "";
}

function needsTranslation(text) {
  const s = String(text || "").trim();
  if (!s) return false;

  // 순수 숫자/기호 셀은 번역하지 않음
  if (!/[A-Za-z가-힣]/.test(s)) return false;

  return true;
}

const blockRegex =
  /<figure\b[\s\S]*?<\/figure>|<table\b[\s\S]*?<\/table>|<caption\b[\s\S]*?<\/caption>|<h[1-6]\b[\s\S]*?<\/h[1-6]>|<br>\s*<header\b[\s\S]*?<\/header>|<header\b[\s\S]*?<\/header>|<br>\s*<footer\b[\s\S]*?<\/footer>|<footer\b[\s\S]*?<\/footer>|<p\b[\s\S]*?<\/p>/gi;

const layoutBlocks = [];
const textUnits = [];

let match;
let fallbackIndex = 1;

while ((match = blockRegex.exec(sourceDocument)) !== null) {
  const rawHtml = match[0];
  const type = classifyBlock(rawHtml);
  const id = getElementId(rawHtml, `b${fallbackIndex++}`);
  const text = htmlToText(rawHtml);
  const fontSize = extractFontSize(rawHtml);
  const drop = shouldDropBlock({ type, text });

  const block = {
    id,
    type,
    text,
    rawHtml,
    fontSize,
    drop,
  };

  if (type === "table") {
    block.rows = extractRowsFromTableHtml(rawHtml, id);
  }

  if (type === "figure") {
    block.imageSrc = extractImageSrc(rawHtml);
    block.rows = extractRowsFromTableHtml(rawHtml, id);
  }

  layoutBlocks.push(block);

  if (drop) continue;

  if (["heading", "paragraph", "list", "caption"].includes(type) && needsTranslation(text)) {
    textUnits.push({
      id,
      type,
      text,
    });
  }

  if (type === "table" && Array.isArray(block.rows)) {
    for (const row of block.rows) {
      for (const cell of row) {
        if (needsTranslation(cell.text)) {
          textUnits.push({
            id: cell.id,
            type: "table_cell",
            text: cell.text,
          });
        }
      }
    }
  }

  if (type === "figure") {
    // figure 내부 chart table의 셀 텍스트만 번역 대상으로 보냅니다.
    if (Array.isArray(block.rows)) {
      for (const row of block.rows) {
        for (const cell of row) {
          if (needsTranslation(cell.text)) {
            textUnits.push({
              id: cell.id,
              type: "figure_table_cell",
              text: cell.text,
            });
          }
        }
      }
    }

    const figcaption = htmlToText(
      (rawHtml.match(/<figcaption\b[\s\S]*?<\/figcaption>/i) || [""])[0]
    );

    if (needsTranslation(figcaption)) {
      textUnits.push({
        id: `${id}_figcaption`,
        type: "figure_caption",
        text: figcaption,
      });
    }
  }
}

if (layoutBlocks.length === 0) {
