/**
 * Rebuild Notion Markdown from Blocks
 *
 * 목적:
 * 1. Solar가 번역한 text unit을 layout block에 다시 합침
 * 2. header/footer는 제거된 상태를 유지
 * 3. table/chart/figure는 Markdown 표로 억지 재구성하지 않고,
 *    Cloudinary secure_url이 있으면 이미지로 삽입
 * 4. 이미지 URL이 없을 때만 fallback 메시지와 chart data를 출력
 */

const base = $("Collect Uploaded Asset URLs").first().json;
const solarResponse = $input.first().json;

let raw =
  solarResponse.choices?.[0]?.message?.content ??
  solarResponse.choices?.[0]?.text ??
  solarResponse.content ??
  solarResponse.text ??
  "";

raw = String(raw).trim();

if (!raw) {
  throw new Error("Solar translation 응답에서 content를 찾지 못했습니다.");
}

raw = raw
  .replace(/^```json\s*/i, "")
  .replace(/^```\s*/i, "")
  .replace(/\s*```$/i, "")
  .trim();

function tryParseJson(text) {
  try {
    return JSON.parse(text);
  } catch {
    return null;
  }
}

function extractJsonObjectText(text) {
  const start = text.indexOf("{");
  const end = text.lastIndexOf("}");

  if (start === -1 || end === -1 || end <= start) {
    return text;
  }

  return text.slice(start, end + 1);
}

let parsed = tryParseJson(raw);

if (!parsed) {
  parsed = tryParseJson(extractJsonObjectText(raw));
}

if (!parsed) {
  throw new Error("번역 JSON 파싱 실패. 응답 앞부분: " + raw.slice(0, 1200));
}

let translations = [];

if (Array.isArray(parsed.translations)) {
  translations = parsed.translations;
} else if (Array.isArray(parsed.blocks)) {
  translations = parsed.blocks;
} else if (Array.isArray(parsed)) {
  translations = parsed;
} else {
  throw new Error("Solar 응답에 translations 배열이 없습니다.");
}

const translationMap = new Map();

for (const item of translations) {
  if (!item || !item.id) continue;
  translationMap.set(String(item.id), String(item.ko || "").trim());
}

const visualAssetUrls = base.visualAssetUrls || {};

function getAssetUrlForBlock(block) {
  const id = String(block.id);
  return visualAssetUrls[id]?.url || "";
}

function escapeHtml(value) {
  return String(value ?? "")
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;");
}

function escapeMdCell(value) {
  return String(value ?? "")
    .replace(/\|/g, "\\|")
    .replace(/\n+/g, " ")
    .trim();
}

function stripBullet(text) {
  return String(text || "")
    .replace(/^[-*·]\s*/, "")
    .trim();
}

function renderMarkdownTable(rows) {
  if (!Array.isArray(rows) || rows.length === 0) return "";

  const textRows = rows.map((row) =>
    row.map((cell) => {
      const translated = translationMap.get(cell.id);
      return translated || cell.text || "";
    })
  );

  const maxCols = Math.max(...textRows.map((r) => r.length));
  const normalized = textRows.map((row) => {
    const next = [...row];
    while (next.length < maxCols) next.push("");
    return next;
  });

  if (normalized.length === 0 || maxCols === 0) return "";

  const header = normalized[0].map(escapeMdCell).join(" | ");
  const sep = Array(maxCols).fill("---").join(" | ");
  const body = normalized
    .slice(1)
    .map((row) => `| ${row.map(escapeMdCell).join(" | ")} |`)
    .join("\n");

  return [`| ${header} |`, `| ${sep} |`, body].filter(Boolean).join("\n");
}

function renderHtmlTable(rows) {
  if (!Array.isArray(rows) || rows.length === 0) return "";

  const renderedRows = rows
    .map((row) => {
      const cells = row
        .map((cell) => {
          const translated = translationMap.get(cell.id);
          const text = translated || cell.text || "";
          const colspan =
            cell.colspan && cell.colspan > 1 ? ` colspan="${cell.colspan}"` : "";
          const rowspan =
            cell.rowspan && cell.rowspan > 1 ? ` rowspan="${cell.rowspan}"` : "";

          return `\t\t<td${colspan}${rowspan}>${escapeHtml(text)}</td>`;
        })
        .join("\n");

      return `\t<tr>\n${cells}\n\t</tr>`;
    })
    .join("\n");

  return [
    '<table fit-page-width="true" header-row="true">',
    renderedRows,
    "</table>",
  ].join("\n");
}

function isReliableTextTable(rows) {
  if (!Array.isArray(rows) || rows.length < 2) return false;

  const colCounts = rows.map((row) => row.length);
  const maxCols = Math.max(...colCounts);
  const minCols = Math.min(...colCounts);

  if (maxCols !== minCols) return false;
  if (maxCols < 2) return false;

  const allCells = rows.flat();

  const suspicious = allCells.some((cell) => {
    const text = String(cell.text || "").trim();

    const metricCount = (
      text.match(/\b(True|False|Positive|Negative|TP|TN|FP|FN|Yes|No)\b/gi) || []
    ).length;

    return text.length > 80 || metricCount >= 4;
  });

  return !suspicious;
}

function renderBlock(block) {
  if (!block || block.drop) return "";

  if (block.type === "heading") {
    const text = translationMap.get(block.id) || block.text || "";
    return `## ${text}`;
  }

  if (block.type === "paragraph") {
    return translationMap.get(block.id) || block.text || "";
  }

  if (block.type === "list") {
    const text = translationMap.get(block.id) || block.text || "";
    return `- ${stripBullet(text)}`;
  }

  if (block.type === "caption") {
    let text = translationMap.get(block.id) || block.text || "";
    text = text.replace(/^Figure\s*/i, "그림 ");
    return `> ${text}`;
  }

  if (block.type === "table") {
    const rows = block.rows || [];
    const assetUrl = getAssetUrlForBlock(block);

    if (assetUrl) {
      const parts = [
        "#### 표",
        "",
        `![원본 표 ${block.id}](${assetUrl})`,
      ];

      if (isReliableTextTable(rows)) {
        parts.push("");
        parts.push("##### 표 텍스트 번역");
        parts.push("");
        parts.push(renderHtmlTable(rows));
      }

      return parts.join("\n");
    }

    if (isReliableTextTable(rows)) {
      return renderHtmlTable(rows);
    }

    return [
      "#### 표",
      "",
      "<callout icon=\"📊\" color=\"gray_bg\">",
      "\t표 영역이 감지되었지만 업로드된 이미지 URL이 없습니다. Cloudinary 업로드 결과와 visualAssetUrls 매핑을 확인해야 합니다.",
      "</callout>",
      "",
      renderMarkdownTable(rows),
    ].filter(Boolean).join("\n");
  }

  if (block.type === "figure" || block.type === "chart") {
    const assetUrl = getAssetUrlForBlock(block);
    const chartTable = renderMarkdownTable(block.rows || []);
    const translatedFigcaption =
      translationMap.get(`${block.id}_figcaption`) || "";

    if (assetUrl) {
      return [
        "#### 그림/차트",
        "",
        `![${escapeMdCell(translatedFigcaption || "그림/차트")}](${assetUrl})`,
        translatedFigcaption ? `\n> ${translatedFigcaption}` : "",
        chartTable ? "\n##### 차트 데이터\n\n" + chartTable : "",
      ].filter(Boolean).join("\n");
    }

    return [
      "#### 그림/차트",
      "",
      "<callout icon=\"📈\" color=\"blue_bg\">",
      "\t차트/그림 영역이 감지되었지만 업로드된 이미지 URL이 없습니다. Cloudinary 업로드 결과와 visualAssetUrls 매핑을 확인해야 합니다.",
      "</callout>",
      chartTable ? "\n##### 차트 데이터\n\n" + chartTable : "",
      translatedFigcaption ? `\n> ${translatedFigcaption}` : "",
    ].filter(Boolean).join("\n");
  }

  return translationMap.get(block.id) || block.text || "";
}

const layoutBlocks = Array.isArray(base.layoutBlocks) ? base.layoutBlocks : [];

const renderedBlocks = layoutBlocks
  .map(renderBlock)
  .filter((x) => String(x || "").trim().length > 0);

const translatedMarkdown = [
  `# ${base.bookTitle || "번역 학습 노트"}`,
  "",
  ...renderedBlocks,
].join("\n\n");

const glossary = Array.isArray(base.glossary) ? base.glossary : [];

const glossaryChecks = glossary.map((term) => {
  const ko = String(term.ko || "").trim();
  const source = String(term.source || "").trim();

  return {
    source,
    ko,
    applied: ko ? translatedMarkdown.includes(ko) : false,
  };
});

const missingTextUnits = Array.isArray(base.textUnits)
  ? base.textUnits
      .filter((unit) => !translationMap.has(unit.id))
      .map((unit) => ({
        id: unit.id,
        type: unit.type,
        preview: String(unit.text || "").slice(0, 100),
      }))
  : [];

const structureChecks = {
  hasHeading: /^#/m.test(translatedMarkdown),
  hasTable:
    translatedMarkdown.includes("![원본 표") ||
    translatedMarkdown.includes("<table") ||
    translatedMarkdown.includes("|"),
  hasFigureCaption:
    translatedMarkdown.includes("그림") ||
    translatedMarkdown.includes("차트") ||
    translatedMarkdown.toLowerCase().includes("figure"),
  hasList: /^-\s+/m.test(translatedMarkdown),
  hasKorean: /[가-힣]/.test(translatedMarkdown),
  hasUploadedTableImage: translatedMarkdown.includes("![원본 표"),
  hasUploadedChartImage: translatedMarkdown.includes("![") && translatedMarkdown.includes("res.cloudinary.com"),
  removedHeaders:
    !translatedMarkdown.includes("CHAPTER ") &&
    !/^>\s*p\.\s*\d+/m.test(translatedMarkdown),
};

return [
  {
    json: {
      ...base,

      translatedMarkdown,
      translationPreview: translatedMarkdown.slice(0, 3000),

      translationMeta: {
        translatedLength: translatedMarkdown.length,
        model: solarResponse.model || "",
        finishReason: solarResponse.choices?.[0]?.finish_reason || "",
        structureChecks,
        appliedGlossaryCount: glossaryChecks.filter((item) => item.applied).length,
        totalGlossaryCount: glossaryChecks.length,
        layoutBlockCount: layoutBlocks.length,
        textUnitCount: Array.isArray(base.textUnits) ? base.textUnits.length : 0,
        translatedUnitCount: translationMap.size,
        missingTextUnitCount: missingTextUnits.length,
        visualAssetUrlMeta: base.visualAssetUrlMeta || null,
      },

      glossaryChecks,
      missingTextUnits,
    },
  },
];

const data = $input.first().json;

const visualAssets = Array.isArray(data.visualAssets)
  ? data.visualAssets
  : [];

const uploadableAssets = visualAssets
  .filter((asset) => asset.base64)
  .map((asset, index) => {
    const mimeType = asset.mimeType || "image/jpeg";

    return {
      assetId: String(asset.id),
      category: asset.category || "image",
      page: asset.page || null,
      mimeType,
      dataUri: `data:${mimeType};base64,${asset.base64}`,
      publicId: `upbook_${Date.now()}_${index}_${asset.category || "asset"}_${asset.id}`,
    };
  });

if (uploadableAssets.length === 0) {
  return [
    {
      json: {
        ...data,
        skipVisualAssetUpload: true,
        visualAssetUrls: {},
      },
    },
  ];
}

return uploadableAssets.map((asset) => ({
  json: asset,
}));

/**
 * Collect Uploaded Asset URLs
 *
 * 목적:
 * 1. Cloudinary 업로드 결과의 secure_url을 수집
 * 2. 원래 visual asset id와 URL을 매핑
 * 3. 다시 하나의 item으로 합쳐서 다음 Solar/Rebuild 노드에 전달
 */

const original = $("Build Structured Translation Body").first().json;

const preparedItems = $("Prepare Visual Assets for Upload")
  .all()
  .map((item) => item.json)
  .filter((item) => !item.skipVisualAssetUpload);

const uploadedItems = $input.all().map((item) => item.json);

const visualAssetUrls = {};

for (let i = 0; i < preparedItems.length; i++) {
  const prepared = preparedItems[i];
  const uploaded = uploadedItems[i] || {};

  const assetId = String(prepared.assetId || "");

  if (!assetId) {
    continue;
  }

  visualAssetUrls[assetId] = {
    id: assetId,
    category: prepared.category || "",
    page: prepared.page || null,
    mimeType: prepared.mimeType || "",
    publicId: uploaded.public_id || prepared.publicId || "",
    url: uploaded.secure_url || uploaded.url || "",
    width: uploaded.width || null,
    height: uploaded.height || null,
    format: uploaded.format || "",
    resourceType: uploaded.resource_type || "",
  };
}

const missingUrls = Object.entries(visualAssetUrls)
  .filter(([id, asset]) => !asset.url)
  .map(([id]) => id);

if (preparedItems.length > 0 && Object.keys(visualAssetUrls).length === 0) {
  throw new Error(
    "Cloudinary 업로드 결과에서 visual asset URL을 수집하지 못했습니다. Upload Visual Assets to Cloudinary 노드 Output을 확인하십시오."
  );
}

return [
  {
    json: {
      ...original,

      visualAssetUrls,

      visualAssetUrlMeta: {
        count: Object.keys(visualAssetUrls).length,
        ids: Object.keys(visualAssetUrls),
        missingUrls,
      },
    },
  },
];
